  ('social-worker-moex-07924', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列那一項不是一個居家服務組織，其「督導員」資格條件之規定？', '["具有醫護相關學歷", "具有服務五年以上專職照顧服務員之經驗，並取得居家服務員結業證書", "具有志願服務工作背景十年以上之經驗，並取得志工教育訓練課程", "具有社會工作相關科系學歷"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
